package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	mu      sync.RWMutex
	accounts map[string]float64
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

func (b *Bank) Deposit(account string, amount float64) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[account] += amount
}

func (b *Bank) Withdraw(account string, amount float64) bool {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.accounts[account] >= amount {
		b.accounts[account] -= amount
		return true
	}
	return false
}

func (b *Bank) Balance(account string) float64 {
	b.mu.RLock()
	defer b.mu.RUnlock()
	return b.accounts[account]
}

func main() {
	bank := NewBank()

	var wg sync.WaitGroup

	wg.Add(3)
	go func() {
		defer wg.Done()
		bank.Deposit("Alice", 100)
	}()

	go func() {
		defer wg.Done()
		if bank.Withdraw("Alice", 50) {
			fmt.Println("Alice withdrew 50")
		}
	}()

	go func() {
		defer wg.Done()
		fmt.Printf("Alice's balance: %.2f\n", bank.Balance("Alice"))
	}()

	wg.Wait()
}